6761   // If a scalar epilogue is required, users outside the loop won't use
6762   // live-outs from the vector loop but from the scalar epilogue. Ignore them if
6763   // that is the case.
6764   bool RequiresScalarEpilogue = requiresScalarEpilogue(true);
6765   auto IsLiveOutDead = [this, RequiresScalarEpilogue](User *U) {
6766     return RequiresScalarEpilogue &&
6767            !TheLoop->contains(cast<Instruction>(U)->getParent());
6768   };
6769 
6770   LoopBlocksDFS DFS(TheLoop);
6771   DFS.perform(LI);
6772   MapVector<Value *, SmallVector<Value *>> DeadInvariantStoreOps;
6773   for (BasicBlock *BB : reverse(make_range(DFS.beginRPO(), DFS.endRPO())))
6774     for (Instruction &I : reverse(*BB)) {
6775       // Find all stores to invariant variables. Since they are going to sink
6776       // outside the loop we do not need calculate cost for them.
6777       StoreInst *SI;
6778       if ((SI = dyn_cast<StoreInst>(&I)) &&
6779           Legal->isInvariantAddressOfReduction(SI->getPointerOperand())) {
6780         ValuesToIgnore.insert(&I);
6781         auto I = DeadInvariantStoreOps.insert({SI->getPointerOperand(), {}});
6782         I.first->second.push_back(SI->getValueOperand());
6783       }
6784 
6785       if (VecValuesToIgnore.contains(&I) || ValuesToIgnore.contains(&I))
6786         continue;
6787 
6788       // Add instructions that would be trivially dead and are only used by
6789       // values already ignored to DeadOps to seed worklist.
