3781 /// Class that provides utilities for VPBlockBases in VPlan.
3782 class VPBlockUtils {
3783 public:
3784   VPBlockUtils() = delete;
3785 
3786   /// Insert disconnected VPBlockBase \p NewBlock after \p BlockPtr. Add \p
3787   /// NewBlock as successor of \p BlockPtr and \p BlockPtr as predecessor of \p
3788   /// NewBlock, and propagate \p BlockPtr parent to \p NewBlock. \p BlockPtr's
3789   /// successors are moved from \p BlockPtr to \p NewBlock. \p NewBlock must
3790   /// have neither successors nor predecessors.
3791   static void insertBlockAfter(VPBlockBase *NewBlock, VPBlockBase *BlockPtr) {
3792     assert(NewBlock->getSuccessors().empty() &&
3793            NewBlock->getPredecessors().empty() &&
3794            "Can't insert new block with predecessors or successors.");
3795     NewBlock->setParent(BlockPtr->getParent());
3796     SmallVector<VPBlockBase *> Succs(BlockPtr->successors());
3797     for (VPBlockBase *Succ : Succs) {
3798       disconnectBlocks(BlockPtr, Succ);
3799       connectBlocks(NewBlock, Succ);
3800     }
3801     connectBlocks(BlockPtr, NewBlock);
3802   }
3803 
3804   /// Insert disconnected block \p NewBlock before \p Blockptr. First
3805   /// disconnects all predecessors of \p BlockPtr and connects them to \p
3806   /// NewBlock. Add \p NewBlock as predecessor of \p BlockPtr and \p BlockPtr as
3807   /// successor of \p NewBlock.
3808   static void insertBlockBefore(VPBlockBase *NewBlock, VPBlockBase *BlockPtr) {
3809     assert(NewBlock->getSuccessors().empty() &&
3810            NewBlock->getPredecessors().empty() &&
3811            "Can't insert new block with predecessors or successors.");
3812     NewBlock->setParent(BlockPtr->getParent());
3813     for (VPBlockBase *Pred : to_vector(BlockPtr->predecessors())) {
3814       disconnectBlocks(Pred, BlockPtr);
3815       connectBlocks(Pred, NewBlock);
3816     }
3817     connectBlocks(NewBlock, BlockPtr);
3818   }
3819 
3820   /// Insert disconnected VPBlockBases \p IfTrue and \p IfFalse after \p
3821   /// BlockPtr. Add \p IfTrue and \p IfFalse as succesors of \p BlockPtr and \p
3822   /// BlockPtr as predecessor of \p IfTrue and \p IfFalse. Propagate \p BlockPtr
3823   /// parent to \p IfTrue and \p IfFalse. \p BlockPtr must have no successors
3824   /// and \p IfTrue and \p IfFalse must have neither successors nor
3825   /// predecessors.
3826   static void insertTwoBlocksAfter(VPBlockBase *IfTrue, VPBlockBase *IfFalse,
3827                                    VPBlockBase *BlockPtr) {
3828     assert(IfTrue->getSuccessors().empty() &&
3829            "Can't insert IfTrue with successors.");
3830     assert(IfFalse->getSuccessors().empty() &&
3831            "Can't insert IfFalse with successors.");
3832     BlockPtr->setTwoSuccessors(IfTrue, IfFalse);
3833     IfTrue->setPredecessors({BlockPtr});
3834     IfFalse->setPredecessors({BlockPtr});
3835     IfTrue->setParent(BlockPtr->getParent());
3836     IfFalse->setParent(BlockPtr->getParent());
3837   }
3838 
3839   /// Connect VPBlockBases \p From and \p To bi-directionally. Append \p To to
3840   /// the successors of \p From and \p From to the predecessors of \p To. Both
3841   /// VPBlockBases must have the same parent, which can be null. Both
3842   /// VPBlockBases can be already connected to other VPBlockBases.
3843   static void connectBlocks(VPBlockBase *From, VPBlockBase *To) {
3844     assert((From->getParent() == To->getParent()) &&
3845            "Can't connect two block with different parents");
3846     assert(From->getNumSuccessors() < 2 &&
3847            "Blocks can't have more than two successors.");
3848     From->appendSuccessor(To);
3849     To->appendPredecessor(From);
3850   }
3851 
3852   /// Disconnect VPBlockBases \p From and \p To bi-directionally. Remove \p To
3853   /// from the successors of \p From and \p From from the predecessors of \p To.
3854   static void disconnectBlocks(VPBlockBase *From, VPBlockBase *To) {
3855     assert(To && "Successor to disconnect is null.");
3856     From->removeSuccessor(To);
3857     To->removePredecessor(From);
3858   }
3859 
3860   /// Return an iterator range over \p Range which only includes \p BlockTy
3861   /// blocks. The accesses are casted to \p BlockTy.
3862   template <typename BlockTy, typename T>
3863   static auto blocksOnly(const T &Range) {
3864     // Create BaseTy with correct const-ness based on BlockTy.
3865     using BaseTy = std::conditional_t<std::is_const<BlockTy>::value,
3866                                       const VPBlockBase, VPBlockBase>;
3867 
3868     // We need to first create an iterator range over (const) BlocktTy & instead
3869     // of (const) BlockTy * for filter_range to work properly.
3870     auto Mapped =
3871         map_range(Range, [](BaseTy *Block) -> BaseTy & { return *Block; });
3872     auto Filter = make_filter_range(
3873         Mapped, [](BaseTy &Block) { return isa<BlockTy>(&Block); });
3874     return map_range(Filter, [](BaseTy &Block) -> BlockTy * {
3875       return cast<BlockTy>(&Block);
3876     });
3877   }
3878 };
